import React from "react";
import FeatureDetail from "./FeatureDetail";

const pageData = {
  title: "SBOM Management",
  subtitle: "Software Bill of Materials for complete supply chain visibility",
  description: "Maintain complete visibility into your software supply chain with comprehensive SBOM management. Track all components, dependencies, licenses, and vulnerabilities across your entire application portfolio. Meet regulatory requirements and protect against supply chain attacks.",
  benefits: [
    "Complete component and dependency inventory",
    "Real-time vulnerability tracking across dependencies",
    "Software supply chain security and integrity verification",
    "Automated license compliance management",
    "Instant vulnerability alerts for affected components"
  ],
  features: [
    { title: "Auto-Discovery", description: "Automatically discover all software components" },
    { title: "Vulnerability Tracking", description: "Monitor known vulnerabilities in all dependencies" },
    { title: "License Compliance", description: "Track and manage open source licenses" },
    { title: "SBOM Generation", description: "Generate SBOM in SPDX, CycloneDX formats" },
    { title: "Supply Chain Security", description: "Verify integrity of your software supply chain" }
  ],
  howItWorks: [
    { title: "Scanning", description: "Codebase is scanned to identify all components" },
    { title: "Inventory Creation", description: "Complete list of dependencies is compiled" },
    { title: "Vulnerability Matching", description: "Components are matched against vulnerability databases" },
    { title: "Alerting", description: "Alerts are generated for new vulnerabilities in your dependencies" }
  ],
  color: "#6366f1",
  icon: "M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01",
  gradient: "from-indigo-500 to-purple-600"
};

function SBOM() {
  return <FeatureDetail {...pageData} />;
}

export default SBOM;
